    % Define the operations as a cell array
    operations = {'+', '-', '*', '/'};

    % Define the corresponding functions
    ops = {
        @(x,y) x + y,
        @(x,y) x - y,
        @(x,y) x * y,
        @(x,y) x / y
    };

    % Find the index of the operation
    index = strmatch(operation, operations);

    % Check if the operation is valid
    if ~isnumeric(index) || index < 1 || index > length(ops)
        error('Invalid operation. Please choose +, -, *, or /.');
    end

    % Perform the operation
    result = ops{index}(a, b);
end

% Example usage:
a = 10;
b = 5;
operation = '+';
result = basicCalculator(operation, a, b);
disp(['The result of ', operation, ' ', num2str(a), ' and ', num2str(b), ' is: ', num2str(result)]);
```

