#include <stdio.h>

int main() {
    int n, i;
    int data[100];

    // Ask the user for the number of elements
    printf("Enter the number of elements you want to enter: ");
    scanf("%d", &n);

    // Ensure the number of elements is within the limit
    if (n > 100) {
        printf("The maximum number of elements is 100.\n");
        return 1;
    }

    // Ask the user to enter the elements
    printf("Enter %d elements:\n", n);
    for (i = 0; i < n; i++) {
        printf("Element %d: ", i + 1);
        scanf("%d", &data[i]);
    }

    // Display the table
    printf("\nGenerated Table:\n");
    for (i = 0; i < n; i++) {
        printf("Element %d: %d\n", i + 1, data[i]);
    }

    return 0;
}
```

This program will prompt the user to enter the number of elements they want to input and then the actual data. It will then display a table showing each element with its corresponding index.

